from pathlib import Path
from html.parser import HTMLParser
class Audit(HTMLParser):
    def __init__(self):
        super().__init__(); self.ids=[]; self.tabs=[]; self.panels=[]
    def handle_starttag(self, tag, attrs):
        a=dict(attrs)
        if 'id' in a: self.ids.append(a['id'])
        if a.get('role')=='tab': self.tabs.append(a)
        if a.get('role')=='tabpanel': self.panels.append(a)
p=Audit(); p.feed(Path('index.html').read_text())
dup={x for x in p.ids if p.ids.count(x)>1}
assert not dup, dup
assert len(p.tabs)==len(p.panels)==9, (len(p.tabs),len(p.panels))
assert {x['aria-controls'] for x in p.tabs}=={x['id'] for x in p.panels}
print('HTML audit: 9 tabs, 9 panels, no duplicate IDs, ARIA targets match')
PY
